public listen(): void {
	if (this.listening) {
		return;
	}
	this.listening = true;
	vscode.workspace.onDidOpenTextDocument(this.openTextDocument, this, this._disposables);
	vscode.workspace.onDidCloseTextDocument(this.onDidCloseTextDocument, this, this._disposables);
	vscode.workspace.onDidChangeTextDocument(this.onDidChangeTextDocument, this, this._disposables);
	vscode.window.onDidChangeVisibleTextEditors(e => {
		for (const { document } of e) {
			const syncedBuffer = this.syncedBuffers.get(document.uri);
			if (syncedBuffer) {
				this.requestDiagnostic(syncedBuffer);
			}
		}
	}, this, this._disposables);

	// Listen for file system changes (e.g., from git branch switches)
	// to refresh diagnostics for affected files
	vscode.workspace.onDidChangeTextDocument(e => {
		// This handles the case where a file on disk has changed and VS Code has reloaded it
		// Clear stale diagnostics and request fresh ones
		if (this.syncedBuffers.has(e.document.uri)) {
			const syncedBuffer = this.syncedBuffers.get(e.document.uri)!;
			// Re-request diagnostics to ensure they're up-to-date with the changed content
			this.requestDiagnostic(syncedBuffer);
		}
	}, this, this._disposables);

	vscode.workspace.textDocuments.forEach(this.openTextDocument, this);
}

