private readonly _onWillChange = this._register(new vscode.EventEmitter<vscode.Uri>());
public readonly onWillChange = this._onWillChange.event;

private fileWatcher: vscode.FileSystemWatcher | undefined;

public listen(): void {
	if (this.listening) {
		return;
	}
	this.listening = true;
	vscode.workspace.onDidOpenTextDocument(this.openTextDocument, this, this._disposables);
	vscode.workspace.onDidCloseTextDocument(this.onDidCloseTextDocument, this, this._disposables);
	vscode.workspace.onDidChangeTextDocument(this.onDidChangeTextDocument, this, this._disposables);
	vscode.window.onDidChangeVisibleTextEditors(e => {
		for (const { document } of e) {
			const syncedBuffer = this.syncedBuffers.get(document.uri);
			if (syncedBuffer) {
				this.requestDiagnostic(syncedBuffer);
			}
		}
	}, this, this._disposables);

	// Watch for file changes on disk (e.g., from git branch switches)
	// This handles files that may not be open in the editor
	const fileExtensions = Array.from(this.modeIds)
		.flatMap(modeId => {
			switch (modeId) {
				case languageModeIds.typescript: return ['*.ts', '*.tsx'];
				case languageModeIds.typescriptreact: return ['*.tsx'];
				case languageModeIds.javascript: return ['*.js', '*.jsx'];
				case languageModeIds.javascriptreact: return ['*.jsx'];
				default: return [];
			}
		});

	if (fileExtensions.length > 0 && vscode.workspace.workspaceFolders) {
		const pattern = `{${fileExtensions.join(',')}}`;
		this.fileWatcher = this._register(
			vscode.workspace.createFileSystemWatcher(pattern)
		);

		// When files change on disk, refresh diagnostics
		this.fileWatcher.onDidChange(uri => {
			const syncedBuffer = this.syncedBuffers.get(uri);
			if (syncedBuffer) {
				// File is open in editor, it will be handled by onDidChangeTextDocument
				return;
			}

			// File is not open, request diagnostics if it's a known file
			if (this.handles(uri)) {
				this.pendingDiagnostics.set(uri, Date.now());
				this.triggerDiagnostics();
			}
		}, this, this._disposables);

		// When files are deleted on disk, clear diagnostics
		this.fileWatcher.onDidDelete(uri => {
			this.client.diagnosticsManager.deleteAllDiagnosticsInFile(uri);
		}, this, this._disposables);
	}

	vscode.workspace.textDocuments.forEach(this.openTextDocument, this);
}

public handles(resource: vscode.Uri): boolean {
	return this.syncedBuffers.has(resource);
}

public ensureHasBuffer(resource: vscode.Uri): boolean {
	if (this.syncedBuffers.has(resource)) {
		return true;
	}

	const existingDocument = vscode.workspace.textDocuments.find(doc => doc.uri.toString() === resource.toString());
	if (existingDocument) {
		return this.openTextDocument(existingDocument);
	}

	return false;
}

public toVsCodeResource(resource: vscode.Uri): vscode.Uri {
	const filepath = this.client.toTsFilePath(resource);
	for (const buffer of this.syncedBuffers.allBuffers) {
		if (buffer.filepath === filepath) {
			return buffer.resource;
		}
	}
	return resource;
}

public toResource(filePath: string): vscode.Uri {
	const buffer = this.syncedBuffers.getForPath(filePath);
	if (buffer) {
		return buffer.resource;
	}
	return vscode.Uri.file(filePath);
}

